SELECT DISTINCT c.funcao AS cargo_direcao FROM cargo c JOIN servidor s ON s.pk_siape = c.fk_siape WHERE LOWER(s.genero) = LOWER('feminino') AND LOWER(COALESCE(s.area_ingresso, s.area_ingresso_og, '')) LIKE '%educacao fisica%' AND ((LOWER(COALESCE(c.campus, '')) LIKE '%formosa%') OR (LOWER(COALESCE(c.sigla_campus, '')) = 'for')) AND (LOWER(c.funcao) LIKE LOWER('%dire%') OR LOWER(COALESCE(c.atividade, '')) LIKE '%dire%') AND c.data_entrada >= DATE('now', '-5 years')